56	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
57	const BLOCK_SIZE = 3;
58	const BLOCK_BASE_PREMIUM = 60;
59	const CURSE_SURCHARGE_RATE = 0.5;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
62	const LOYALTY_THRESHOLD_YEARS = 2;
63	const LOYALTY_DISCOUNT_RATE = 0.2;
64	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
65	
66	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
67	
68	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
69	
70	const componentGroupBasePremium = (type: string, count: number): number =>
71	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
72	
73	const sumItemBasePremiums = (items: Item[]): number => {
74	  const componentCounts = new Map<string, number>();
75	  let total = 0;
76	  for (const item of items) {
77	    if (isComponent(item)) {
78	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
79	    } else {
80	      total += itemBasePremium(item);
81	    }
82	  }
83	  for (const [type, count] of componentCounts) {
84	    total += componentGroupBasePremium(type, count);
85	  }
86	  return total;
87	};
88	
89	const isHighlyEnchanted = (item: Item): boolean =>
90	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
91	
92	const itemSurcharges = (item: Item): number => {
93	  const base = itemBasePremium(item);
94	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
95	  const enchantmentSurcharge = isHighlyEnchanted(item)
96	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
97	    : 0;
98	  return curseSurcharge + enchantmentSurcharge;
99	};
100	
101	const sumItemSurcharges = (items: Item[]): number =>
102	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
103	
104	const firstInsuranceSurchargeOn = (baseTotal: number): number =>
105	  baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
106	
107	export type Customer = { yearsWithMHPCO: number };
108	
109	const isLoyal = (customer: Customer): boolean =>
110	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
111	
112	const loyaltyDiscountOn = (baseTotal: number, customer: Customer): number =>
113	  isLoyal(customer) ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
114	
115	const quoteStep = (
116	  step: QuoteStep,
117	  customer: Customer,
118	  isFollowUp: boolean,
119	): QuoteResult => {
120	  const baseTotal = sumItemBasePremiums(step.items);
121	  const itemSurchargesTotal = sumItemSurcharges(step.items);
122	  const firstInsurance = firstInsuranceSurchargeOn(baseTotal);
123	  const loyaltyDiscount = loyaltyDiscountOn(baseTotal, customer);
124	  const followUpDiscount = isFollowUp ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
125	  const premium = Math.ceil(
126	    baseTotal +
127	      itemSurchargesTotal +
128	      firstInsurance -
129	      loyaltyDiscount -
130	      followUpDiscount +
131	      PROCESSING_FEE,
132	  );
133	  return { premium };
134	};
135	
136	type Policy = { items: Item[]; remainingCap: number };
137	
138	const policyInsuranceSum = (items: Item[]): number =>
139	  items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
140	
141	const createPolicy = (items: Item[]): Policy => ({
142	  items,
143	  remainingCap: policyInsuranceSum(items) * CAP_MULTIPLIER,
144	});
145	
146	const claimStep = (step: ClaimStep, policy: Policy): ClaimResult => {
147	  let payout = 0;
148	  for (const damage of step.incident.damages) {
149	    payout += Math.max(0, damage.amount - DEDUCTIBLE);
150	  }
151	  policy.remainingCap -= payout;
152	  return { payout, remainingCap: policy.remainingCap };
153	};
154	
155	export const runScenario = (scenario: Scenario): ScenarioResult => {
156	  let quoteCount = 0;
157	  const policies: Policy[] = [];
158	  const results: StepResult[] = scenario.steps.map((step) => {
159	    if (step.op === "claim") return claimStep(step, policies[step.policy]);
160	    const isFollowUp = quoteCount > 0;
161	    quoteCount += 1;
162	    policies.push(createPolicy(step.items));
163	    return quoteStep(step, scenario.customer, isFollowUp);
164	  });
165	  return { results };
166	};
