const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const sumDamagePayouts = (damages: Damage[]): number =>
  damages.reduce((sum, damage) => sum + damagePayout(damage), 0);

const claimStep = (step: ClaimStep, policy: Policy): ClaimResult => {
  const payout = sumDamagePayouts(step.incident.damages);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};
